-- 364_buildout_m36.sql (GENERATED) — fill empty lessons for "Drone Surveying — UAS for Land Surveying"
-- Module da5e0001-0000-0000-0000-000000000001. Namespaced by tag 'buildout' / created_by 'buildout:m36' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='da5e0001-0000-0000-0000-000000000001' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='da5e0001-0000-0000-0000-000000000001' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='da5e0001-0000-0000-0000-000000000001' AND created_by='buildout:m36';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A UAS is the aircraft, sensor payload, ground control station, and data link working as one system.','Drones collect dense, high-resolution data quickly and safely, but the data still requires professional interpretation.','In Texas, boundary determinations and certified surveys require an RPLS regardless of how the data was captured.']::text[], learning_objectives=ARRAY['Define unmanned aircraft systems (UAS) and explain their role in modern land surveying.','Describe the primary survey deliverables produced from drone data.','Identify where UAS fits within a surveyor''s workflow and where a licensed surveyor remains essential.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b01-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b01-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Commercial drone surveying in the U.S. requires a Part 107 Remote Pilot Certificate.','Standard Part 107 limits: <=400 ft AGL, daylight/civil twilight, VLOS, <=100 mph, one aircraft per pilot.','Flights in controlled airspace (Class B/C/D/E surface) need authorization, usually via LAANC.']::text[], learning_objectives=ARRAY['Summarize the core operating rules of 14 CFR Part 107 for small UAS.','Classify controlled and uncontrolled airspace and explain when authorization is required.','Describe LAANC and the process for obtaining airspace authorization and waivers.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b02-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b02-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Multirotors offer precise positioning and VTOL; fixed-wings offer endurance and area coverage.','The sensor choice (RGB vs LiDAR vs multispectral) is driven by the deliverable required.','Onboard RTK/PPK GNSS and an IMU georeference each image, reducing reliance on dense ground control.']::text[], learning_objectives=ARRAY['Compare multirotor and fixed-wing platforms for surveying missions.','Distinguish RGB, multispectral, thermal, and LiDAR payloads and their uses.','Explain the role of onboard GNSS (RTK/PPK) and the IMU in georeferencing.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b03-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b03-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Flight altitude sets GSD; lower flights give finer detail but cover less ground per pass.','Typical survey overlap is 70-80% front and 60-75% side; increase it over vegetation and uniform terrain.','Plan with margins: wind, battery reserve, takeoff/landing, and turn time all reduce productive coverage.']::text[], learning_objectives=ARRAY['Plan flight altitude to achieve a target GSD for a given camera.','Select front and side overlap appropriate to terrain and vegetation.','Estimate flight time, number of images, and battery requirements for a mission.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b04-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b04-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['GCPs tie the photogrammetric model to a real-world datum; checkpoints independently verify accuracy.','Distribute GCPs across the site and at elevation extremes; never cluster them in one area.','Even with an RTK drone, surveyors place checkpoints to validate absolute accuracy.']::text[], learning_objectives=ARRAY['Explain the purpose of ground control points (GCPs) and independent checkpoints.','Describe how to lay out, target, and observe GCPs across a project.','Relate UAS georeferencing to a project datum and the role of RTK/PPK base stations.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b05-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b05-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Photogrammetry recovers 3D geometry from the parallax between overlapping images.','SfM solves camera positions and a sparse cloud first, then densifies to a full point cloud.','Bundle adjustment simultaneously refines camera poses, calibration, and 3D point coordinates.']::text[], learning_objectives=ARRAY['Explain the photogrammetric principle of recovering 3D positions from overlapping 2D images.','Describe the Structure-from-Motion (SfM) workflow: feature matching, bundle adjustment, dense cloud.','Define interior and exterior orientation and the role of camera calibration.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b06-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b06-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['LiDAR actively measures range with laser pulses and can return multiple echoes per pulse.','Multiple returns let LiDAR see through vegetation gaps to recover bare-earth elevations.','Accuracy depends on tight GNSS/IMU integration and boresight calibration of the sensor.']::text[], learning_objectives=ARRAY['Explain how airborne LiDAR measures range and builds a point cloud.','Contrast LiDAR with photogrammetry for vegetation penetration and bare-earth mapping.','Describe the integration of laser scanner, GNSS, and IMU and the need for boresight calibration.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b07-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b07-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['The workflow is: import & align -> add/mark control -> optimize -> densify -> classify -> generate products.','Marking GCPs accurately and re-optimizing is the step that locks accuracy.','Watch reprojection error, GCP residuals, and point-cloud noise as quality flags.']::text[], learning_objectives=ARRAY['Outline the end-to-end processing workflow from raw images to deliverables.','Explain GCP marking, optimization, and point-cloud classification steps.','Identify common processing errors and quality flags to watch for.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b08-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b08-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['An orthomosaic is a scale-true, measurable image; a raw aerial photo is not.','A DSM includes everything (vegetation, buildings); a DTM is bare earth only.','Contours and breaklines are derived from the DTM, not the DSM.']::text[], learning_objectives=ARRAY['Define orthomosaic, DSM, and DTM and explain how each is produced.','Distinguish a surface model (DSM) from a bare-earth model (DTM).','Generate contours and breaklines from elevation models for survey deliverables.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b09-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b09-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['UAS topo can meet tight contour standards when GSD, overlap, and control are adequate.','Volumes are computed between a measured surface and a chosen base surface.','The base-surface choice (best-fit plane, lowest point, or a prior survey) strongly affects the answer.']::text[], learning_objectives=ARRAY['Plan a UAS topographic survey to meet a contour-interval accuracy standard.','Compute stockpile and earthwork volumes from UAS surfaces.','Explain base-surface selection and its effect on volume results.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b0a-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b0a-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Drones support pre-design topo, progress monitoring, earthwork tracking, and as-built documentation.','Corridor (linear) projects use long, narrow flight plans with extra sidelap and control.','UAS data integrates with BIM/CAD design surfaces for cut/fill and progress comparison.']::text[], learning_objectives=ARRAY['Describe UAS applications across the construction project lifecycle.','Explain corridor mapping for roads, pipelines, and transmission lines.','Relate UAS deliverables to design surfaces, progress tracking, and as-builts.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b0b-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b0b-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Accuracy is measured on independent checkpoints, not GCPs used in the adjustment.','RMSE from checkpoint residuals is the standard accuracy statistic (per ASPRS).','A professional deliverable includes products, metadata, an accuracy report, and the surveyor''s certification.']::text[], learning_objectives=ARRAY['Distinguish absolute vs relative and horizontal vs vertical accuracy.','Compute RMSE from checkpoint residuals and relate it to accuracy standards.','Assemble a complete, well-documented UAS deliverable package.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b0c-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b0c-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=50, key_takeaways=ARRAY['Mastery means connecting regulation, flight planning, processing, and accuracy into one defensible workflow.','Quantitative skills (GSD, footprint, coverage, RMSE) underpin every UAS deliverable.','A drone gathers data; an RPLS certifies the survey.']::text[], learning_objectives=ARRAY['Integrate knowledge of UAS platforms, regulations, planning, processing, and QA.','Apply GSD, footprint, coverage, and accuracy computations to realistic scenarios.','Evaluate when a deliverable requires a licensed surveyor''s certification.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da5e0b0d-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='da5e0b0d-0000-0000-0000-000000000001';
  'eeee3650-0000-0000-0000-000000000001', 'Ground Sample Distance from camera and flight height', 'Ground Sample Distance from camera and flight height', 'Drone Surveying — Flight Planning', 'GSD', 'numeric_input', 'medium', 'A survey camera has a pixel pitch of {{pix:f1}} micrometers and a focal length of {{foc:f1}} mm. The drone flies at {{height:f0}} m above ground level. Compute the ground sample distance (GSD) in cm/pixel.', '(pix*height)/(foc*10)', '{"decimals":2,"unit":"cm/pixel","tolerance":0.05}', '[{"name":"pix","type":"float","min":2.4,"max":6,"decimals":1},{"name":"foc","type":"float","min":8,"max":35,"decimals":1},{"name":"height","type":"integer","min":60,"max":120}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"GSD formula","formula":"GSD = (pixel_um x H_m) / (focal_mm x 10)","calculation_template":"({{pix:f1}} x {{height:f0}}) / ({{foc:f1}} x 10)"},{"step_number":2,"title":"Compute","result_template":"GSD = {{_answer}} cm/pixel"}]'::jsonb, '{"method":"none"}'::jsonb, 'GSD = (pixel_um x H) / (focal_mm x 10) = ({{pix:f1}} x {{height:f0}}) / ({{foc:f1}} x 10) = {{_answer}} cm/pixel.', 'da5e0001-0000-0000-0000-000000000001', ARRAY['buildout','module-36','practice']::text[], true, 'buildout:m36');
  'eeee3650-0000-0000-0000-000000000002', 'Image ground footprint from GSD and sensor width', 'Image ground footprint from GSD and sensor width', 'Drone Surveying — Flight Planning', 'Image footprint', 'numeric_input', 'easy', 'At a GSD of {{gsd:f1}} cm/pixel, a camera sensor is {{width:f0}} pixels wide. Compute the ground footprint width of one image in meters.', '(gsd*width)/100', '{"decimals":1,"unit":"m","tolerance":0.5}', '[{"name":"gsd","type":"float","min":1.5,"max":5,"decimals":1},{"name":"width","type":"integer","min":4000,"max":8000}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Footprint formula","formula":"footprint = GSD x sensor_width_px","calculation_template":"{{gsd:f1}} cm/px x {{width:f0}} px = (result) cm"},{"step_number":2,"title":"Convert to meters","result_template":"footprint = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Footprint = GSD x sensor width = {{gsd:f1}} cm/px x {{width:f0}} px = {{_answer}} m (after dividing cm by 100).', 'da5e0001-0000-0000-0000-000000000001', ARRAY['buildout','module-36','practice']::text[], true, 'buildout:m36');
  'eeee3650-0000-0000-0000-000000000003', 'Number of flight lines across a site', 'Number of flight lines across a site', 'Drone Surveying — Flight Planning', 'Coverage', 'numeric_input', 'medium', 'A site is {{site:f0}} m wide. Each image footprint is {{foot:f0}} m wide and you plan {{side:f0}}% side overlap. How many parallel flight lines are needed to cover the width? (line spacing = footprint x (1 - sidelap); round up.)', 'ceil(site/spacing)', '{"decimals":0,"unit":"lines","tolerance":0}', '[{"name":"site","type":"integer","min":300,"max":900},{"name":"foot","type":"integer","min":120,"max":200},{"name":"side","type":"integer","min":60,"max":75}]'::jsonb, '[{"name":"spacing","formula":"foot*(1-side/100)"}]'::jsonb, '[{"step_number":1,"title":"Line spacing","formula":"spacing = footprint x (1 - sidelap)","calculation_template":"{{foot:f0}} x (1 - {{side:f0}}/100) = {{spacing:f1}} m"},{"step_number":2,"title":"Number of lines","result_template":"ceil({{site:f0}} / {{spacing:f1}}) = {{_answer}} lines"}]'::jsonb, '{"method":"none"}'::jsonb, 'Line spacing = {{foot:f0}} x (1 - {{side:f0}}/100) = {{spacing:f1}} m. Lines = ceil({{site:f0}} / {{spacing:f1}}) = {{_answer}}.', 'da5e0001-0000-0000-0000-000000000001', ARRAY['buildout','module-36','practice']::text[], true, 'buildout:m36');
  'eeee3650-0000-0000-0000-000000000004', 'Number of batteries for a mission', 'Number of batteries for a mission', 'Drone Surveying — Flight Planning', 'Battery budget', 'numeric_input', 'medium', 'Total flight time for a mission is estimated at {{total:f0}} minutes. Each battery provides {{usable:f0}} minutes of usable flight before the landing reserve. How many batteries are required? (round up.)', 'ceil(total/usable)', '{"decimals":0,"unit":"batteries","tolerance":0}', '[{"name":"total","type":"integer","min":60,"max":180},{"name":"usable","type":"integer","min":15,"max":28}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Batteries needed","formula":"batteries = ceil(total / usable per battery)","calculation_template":"ceil({{total:f0}} / {{usable:f0}})"},{"step_number":2,"title":"Result","result_template":"batteries = {{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'batteries = ceil(total / usable) = ceil({{total:f0}} / {{usable:f0}}) = {{_answer}}. Always plan a landing reserve, so divide by USABLE minutes.', 'da5e0001-0000-0000-0000-000000000001', ARRAY['buildout','module-36','practice']::text[], true, 'buildout:m36');
COMMIT;
SELECT 'm36 Drone Surveying — UAS for Land Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='da5e0001-0000-0000-0000-000000000001') || ' blocks.' AS status;