INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3660-0000-0000-0000-000000000001', 'A survey camera has a pixel pitch of {{pix:f1}} micrometers and a focal length of {{foc:f1}} mm. The drone flies at {{height:f0}} m above ground level. Compute the ground sample distance (GSD) in cm/pixel.', 'numeric_input', '[]'::jsonb, '0', 'GSD = (pixel_um x H) / (focal_mm x 10) = ({{pix:f1}} x {{height:f0}}) / ({{foc:f1}} x 10) = {{_answer}} cm/pixel.', 'medium', 'da5e0001-0000-0000-0000-000000000001', NULL, ARRAY['buildout','module-36','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3650-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3660-0000-0000-0000-000000000002', 'At a GSD of {{gsd:f1}} cm/pixel, a camera sensor is {{width:f0}} pixels wide. Compute the ground footprint width of one image in meters.', 'numeric_input', '[]'::jsonb, '0', 'Footprint = GSD x sensor width = {{gsd:f1}} cm/px x {{width:f0}} px = {{_answer}} m (after dividing cm by 100).', 'easy', 'da5e0001-0000-0000-0000-000000000001', NULL, ARRAY['buildout','module-36','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3650-0000-0000-0000-000000000002', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3660-0000-0000-0000-000000000003', 'A site is {{site:f0}} m wide. Each image footprint is {{foot:f0}} m wide and you plan {{side:f0}}% side overlap. How many parallel flight lines are needed to cover the width? (line spacing = footprint x (1 - sidelap); round up.)', 'numeric_input', '[]'::jsonb, '0', 'Line spacing = {{foot:f0}} x (1 - {{side:f0}}/100) = {{spacing:f1}} m. Lines = ceil({{site:f0}} / {{spacing:f1}}) = {{_answer}}.', 'medium', 'da5e0001-0000-0000-0000-000000000001', NULL, ARRAY['buildout','module-36','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3650-0000-0000-0000-000000000003', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3660-0000-0000-0000-000000000004', 'Total flight time for a mission is estimated at {{total:f0}} minutes. Each battery provides {{usable:f0}} minutes of usable flight before the landing reserve. How many batteries are required? (round up.)', 'numeric_input', '[]'::jsonb, '0', 'batteries = ceil(total / usable) = ceil({{total:f0}} / {{usable:f0}}) = {{_answer}}. Always plan a landing reserve, so divide by USABLE minutes.', 'medium', 'da5e0001-0000-0000-0000-000000000001', NULL, ARRAY['buildout','module-36','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3650-0000-0000-0000-000000000004', 0.5);
